var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어떻게 된 거죠? 지금 저 분이 저희 대신 싸우고 있는 건가요?","JPN":"どういうことですか？　今あの人が私たちの代わりに戦ってくれているのですか？","ENG":"What's going on? Is that person fighting for us?","TWN":"怎麼回事？她為什麼要幫我們戰鬥？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나도 몰라. 저런 커다란 갑옷이 지원군으로 올 거란 얘긴 못 들었으니까.","JPN":"私も知らない。あんな大きな鎧が助っ人で来るとは聞いてないから。","ENG":"I don't know. I didn't hear anything about some heavy-armored reinforcement coming.","TWN":"不知道。我可沒聽說那個大塊頭會來支援我們。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"엄청 강한 사람 같은데요? 스완이 아까처럼 대응도 못하고 도망치고 있잖아요.","JPN":"とても強い人みたいですね？　スワンがさっきとは打って変わって逃げ回っているじゃないですか。","ENG":"But she's really strong! Swan's running away, unlike when she was fighting us.","TWN":"她看起來很強喔？剛剛還從容不迫的史旺現在只能疲於躲避。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"확실히 아까보다 덜 적극적이긴 하네.","JPN":"確かに、さっきよりは消極的になってるね。","ENG":"She is definitely less active than before.","TWN":"確實沒有剛才那麼咄咄逼人了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하지만 스완은… 그런 기습을 당하고도 전혀 당황한 기색이 아니었어.","JPN":"でもスワンは……不意打ちを受けたのに全然慌てるような様子じゃなかった。","ENG":"But Swan... wasn't even fazed by that ambush.","TWN":"但是史旺……在受到突襲後依然顯得很從容。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"벌써 여기까지 오다니.","JPN":"もうここまで来るとは。","ENG":"It's incredible how you made it here so fast.","TWN":"真不敢相信已經走到這一步了。"},"stage":{"bg":"CORRIDOR_04","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"단신으로 마왕에 맞선 이 답게, 그림자가 되었어도 정말 굉장한 힘이네요.","JPN":"一人で魔王に立ち向かった者らしく、シャドウになっても凄まじい力ですね。","ENG":"As someone who fought against the Demon Lord alone, your strength is incredible, even after becoming a Shadow.","TWN":"不愧是孤身一人對抗過魔王的存在，即便變成了暗影也依然強得嚇人。"},"stage":{"bg":"CORRIDOR_04","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나를 기다린 것치곤 도망만 치고 있구나.","JPN":"我を待ち受けていたわりには逃げてばかりいるな。","ENG":"For someone who has been waiting for me, all you do is run away.","TWN":"你不是在等我嗎？為何一味逃跑。"},"stage":{"bg":"CORRIDOR_04","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이런 나약한 침식체들을 방패 삼아 어디까지 숨으려는 거지?","JPN":"こんな軟弱な侵食体を盾にしていつまで隠れるつもりなのか。","ENG":"How much longer are you going to hide behind these weak C.O.s?","TWN":"你要躲在這些羸弱的侵蝕體身後多久？"},"stage":{"bg":"CORRIDOR_04","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"충분히 도망쳤어요. 이 뒤는 타기리온의 마지막 봉인이 있는 막다른 길이거든요.","JPN":"ここまで逃げれば十分です。この先はタギリオンの最後の封印がある行き止まりですから。","ENG":"I won't run anymore. Behind me is a dead end where the last seal of Thagirion is.","TWN":"逃得足夠遠了。再往後就是死路，那裡有塔基里翁最後一個封印。"},"stage":{"bg":"CORRIDOR_04","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"타기리온의 안식을 방해할 셈인가!","JPN":"タギリオンの安息を妨げるつもりか！","ENG":"You dare interrupt Thagirion's slumber?!","TWN":"你想打擾塔基里翁的安息嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"안식이라고요?","JPN":"安息ですって？","ENG":"Slumber?","TWN":"安息？"},"stage":{"bg":"CORRIDOR_04","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마왕 타기리온을 가두는 건 그녀의 안식이 아닌 당신을 위한 것 아닌가요?","JPN":"魔王タギリオンを閉じ込めておくことは、彼女のためではなく、自分のためではないんですか？","ENG":"Sealing the Demon Lord Thagirion was not for her slumber, but for your own sake.","TWN":"封印魔王塔基里翁不是為了她的安息，而是為了你不是嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네놈…!","JPN":"貴様……！","ENG":"You...!","TWN":"你……！"},"stage":{"bg":"CORRIDOR_04","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_32"},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이곳은 클리파 차원의 에너지가 가장 강력한 곳.","JPN":"ここはクリファ次元のエネルギーが最も強力な場所。","ENG":"This is where the Qlipha Dimension energy is the strongest.","TWN":"這裡是逆卡巴拉次元的能量最為強烈的地方。"},"stage":{"bg":"CORRIDOR_04","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저에겐 막다른 길이지만, 당신의 고향과 가장 가까운 문턱이기도 하죠.","JPN":"この先は行き止まりですが、あなたにとっては故郷に最も近い扉でもありますね。","ENG":"It may be a dead end for me, but it is the closest threshold to your home.","TWN":"對我來說雖然是死路，但同時也是與你的故鄉最為接近的門檻。"},"stage":{"bg":"CORRIDOR_04","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금부터 마주하게 되는 건, 가장 찬란했던 모습의 당신일 겁니다.","JPN":"今から対峙するのは、最も輝いていたころのあなたでしょう。","ENG":"You are about to face yourself in your prime.","TWN":"從這開始，你將面對最為輝煌的自己。"},"stage":{"bg":"CORRIDOR_04","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"여긴…? 겨울의 땅인가?","JPN":"ここは……？　冬の地なのか？","ENG":"This is...? The Gelid Lands?","TWN":"這裡是……？冬境？"},"stage":{"bg":"NOMAD_BORDER","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"아니, 그럴 리 없다. 이것은 그 여인의 말대로 과거의 잔영이로군.","JPN":"いや、そんなはずはない。これはあの女の言う通り過去の残影であろう。","ENG":"No. It cannot be. This must be the remnants of the past that woman was talking about.","TWN":"不，不可能。正如那個女人所說，這裡是過去的殘影。"},"stage":{"bg":"NOMAD_BORDER","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그렇다는 건…","JPN":"ということは……","ENG":"Then that means...","TWN":"這表示……"},"stage":{"bg":"NOMAD_BORDER","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 방금 통로 안쪽이 번쩍했어요.","JPN":"あっ、今通路の奥が光りました。","ENG":"Oh? Something just flashed inside the tunnel.","TWN":"啊，我剛看見通道裡閃了一道光。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"뭔가 날아온다. 피해!","JPN":"何かが飛んでくる。避けて！","ENG":"Something headed toward us! Duck!","TWN":"有東西飛過來了，快躲開！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꺄앗?!","JPN":"きゃあっ！？","ENG":"Kyahh?!","TWN":"啊啊？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어… 어라? 방금 그 커다란 갑옷이잖아요?","JPN":"あ……あれ？　今のはあの大きい鎧ですよね？","ENG":"W-what? It's that huge armor.","TWN":"呃……什麼？那不是剛才的大塊頭嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"대체 무슨 수로 저기서 날아온 거지?","JPN":"一体どうやってあそこから飛んできたんだ？","ENG":"How did she fly all the way over to here from there?","TWN":"她怎麼從那裡飛過來了？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이봐, 괜찮아?","JPN":"おい、大丈夫か？","ENG":"Are you okay?","TWN":"喂，沒事吧？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 다시 일어섰다.","JPN":"あっ、また立ち上がった。","ENG":"Oh, she's back up again.","TWN":"哎呀，又站起來了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…물러서라, 소녀들아.","JPN":"……下がれ、少女たちよ。","ENG":"...Stand back, girls.","TWN":"……你們退下。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나의 오랜 과오가 적개심을 품은 채 다가오고 있으니.","JPN":"我の古き過ちが敵愾心を抱いて近づいてくる。","ENG":"My entrenched errors are approaching me with animosity.","TWN":"我的老毛病又犯了。我過去犯下的過錯正滿懷憎恨朝我走來。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"낯선 장소와 낯설지 않은 계절이구나.","JPN":"見慣れぬ場所に、見慣れた季節だ。","ENG":"An unfamiliar place, but a familiar season.","TWN":"陌生的場所，熟悉的季節。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그대들이 감히 성역을 침범하려 드는가!","JPN":"そなたたちは何故聖域を侵犯するのか！","ENG":"You dare to invade the sanctuary?!","TWN":"你們竟敢侵犯聖域！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"침범이라고? 누가 누구더러 하는 소리야?","JPN":"侵犯って？　誰に向けたセリフを言ってるんだ？","ENG":"Invade? Look who's talking!","TWN":"侵犯？你是不是搞錯了？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"맞아요! 우리 세계에 온 건 그쪽이거든요!","JPN":"そうですよ！　私たちの世界に来たのはそっちですよ！","ENG":"Yeah! You're the one who's invading our world!","TWN":"沒錯，明明是你來到了我們的世界！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"소용없어요.","JPN":"無駄です。","ENG":"It is futile.","TWN":"沒用的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"거울 이면의 존재에게 이 세계의 당신들은 그저 괴성을 지르는 괴물로 보일 뿐입니다.","JPN":"鏡の裏側の存在にとってこの世界のあなたたちは、ただ奇声を発している怪物にしか見えません。","ENG":"You are just a screaming monster to the reflections from the other side of the mirror.","TWN":"對於鏡子另一面的存在來說，你們只是一個只會亂叫的怪物。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"거울이라고? 그렇다면 저것도 누군가가 투영된 모습이란 말이야?","JPN":"鏡だと？　ならあれも誰かの投影された姿だということ？","ENG":"Mirror? You mean that's also someone's reflection?","TWN":"鏡子？這麼說她也是別人的倒影？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"맞아요. 그녀는 오랫동안 방황하던 그림자 모르스의 과거.","JPN":"そうです。彼女は長い間彷徨っていたシャドウ、モールスの過去。","ENG":"Indeed. She is the ever-wandering Mors' past.","TWN":"沒錯，她是過去的死神，一個到處流浪的暗影。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"엘리시온의 신성에 가장 범접했던 인간이자, 타기리온의 마지막 봉인을 푸는 열쇠입니다.","JPN":"エリシオンの神聖に最も近づいた人間であり、タギリオンの最後の封印を解く鍵です。","ENG":"The human who came closest to Elysion's divinity, and the key to Thagirion's last seal.","TWN":"最接近艾利森神性的人類，也是開啟塔基里翁最終封印的鑰匙。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};